-- ROMRxBJJ ROM Thresholds — 569 rows (one per technique-joint pair)
-- Source: Google Sheet ROM_Thresholds_Map
-- Used by compute-tiers edge function for tier calculation

CREATE TABLE IF NOT EXISTS public.rom_thresholds (
  id              UUID PRIMARY KEY DEFAULT extensions.uuid_generate_v4(),
  technique_code  TEXT NOT NULL,
  technique_name  TEXT,
  belt            TEXT,
  category        TEXT,
  joint           TEXT NOT NULL,
  required_value  NUMERIC,
  laterality_rule TEXT,
  tier_logic_note TEXT,
  created_at      TIMESTAMPTZ NOT NULL DEFAULT now()
);
ALTER TABLE public.rom_thresholds ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Authenticated read rom_thresholds"
  ON public.rom_thresholds FOR SELECT USING (auth.role() = 'authenticated');

